# %% ../../nbs/25_wuilt_routes.ipynb #store-list
@rt("/")
def get():
    with get_session() as session:
        stores = session.exec(select(WuiltStore)).all()
    return Titled(
        "Wuilt Stores",
        Div(
            H2("Wuilt Store Manager"),
            A("Add Store", href="/add", style="margin-left: 1rem"),
            style="display: flex; align-items: center;"
        ),
        Table(
            Tr(Th("ID"), Th("Name"), Th("Store ID"), Th("Locale"), Th("Actions")),
            *[Tr(
                Td(str(s.id)),
                Td(s.name),
                Td(s.store_id),
                Td(s.locale),
                Td(
                    A("Products", href=f"/stores/{s.id}"),
                    " | ",
                    A("Sync", href=f"/sync/{s.id}"),
                    " | ",
                    A("Delete", href=f"/delete/{s.id}",
                      hx_confirm="Delete this store?"),
                ),
            ) for s in stores],
        ) if stores else P("No stores registered yet."),
        Br(),
        A("Back to Home", href="/"),
    )

